import React, { useState } from "react";
import { 
  Card, 
  Typography, 
  Space, 
  Select, 
  Button, 
  Input, 
  Table, 
  Tag, 
  theme, 
  Divider,
  Row,
  Col,
  message
} from "antd";
import { 
  ControlOutlined, 
  SyncOutlined, 
  BulbOutlined, 
  UnlockOutlined, 
  SearchOutlined,
  ExportOutlined 
} from "@ant-design/icons";
import { useI18n } from "@/framework/i18n/hooks";
import { mockStorages, StorageInfo } from "../dashboard/data/mockData";
import { exportToExcel } from "../../utils/exportExcel";

const { Title, Text } = Typography;

export default function ControlPage() {
  const { token } = theme.useToken();
  const { t } = useI18n(["storageLocker", "platform", "common"]);
  const [selectedRowKeys, setSelectedRowKeys] = useState<React.Key[]>([]);
  const [searchText, setSearchText] = useState("");
  
  // Control Select States
  const [fanMode, setFanMode] = useState("auto");
  const [lampMode, setLampMode] = useState("led1_on");

  const onSelectChange = (newSelectedRowKeys: React.Key[]) => {
    setSelectedRowKeys(newSelectedRowKeys);
  };

  const handleBatchControl = (type: string, val: string) => {
    if (selectedRowKeys.length === 0) {
      message.warning(t("dashboard.selectPlaceholder", { ns: "storageLocker" }));
      return;
    }
    
    const count = selectedRowKeys.length;
    const unit = t("common:unit_device");
    const processing = t("dashboard.ctrlProcessing", { ns: "storageLocker" });
    const success = t("dashboard.ctrlSuccess", { ns: "storageLocker" });
    
    message.loading(`${count}${unit} ${type} ${processing}`, 1.5);
    
    setTimeout(() => {
      message.success(`${count}${unit} ${type} ${success}`);
      setSelectedRowKeys([]);
    }, 2000);
  };

  const handleExportXlsx = async () => {
    const success = await exportToExcel(mockStorages, "Locker_Control_List");
    if (success) {
      message.success(`${t("common:exportXlsx")} ${t("dashboard.ctrlSuccess", { ns: "storageLocker" })}`);
    }
  };

  const filteredData = mockStorages.filter(item => 
    item.name.toLowerCase().includes(searchText.toLowerCase()) || 
    item.address.toLowerCase().includes(searchText.toLowerCase())
  );

  const columns = [
    {
      title: t("dashboard.lockerName", { ns: "storageLocker" }),
      dataIndex: "name",
      key: "name",
      render: (text: string) => <Text strong>{text}</Text>,
    },
    {
      title: t("dashboard.status", { ns: "storageLocker" }),
      dataIndex: "connectState",
      key: "connectState",
      render: (state: string) => (
        <Tag color={state === "on" ? "success" : "error"}>
          {state === "on" ? t("dashboard.on", { ns: "storageLocker" }) : t("dashboard.off", { ns: "storageLocker" })}
        </Tag>
      ),
    },
    {
      title: t("dashboard.fan", { ns: "storageLocker" }),
      dataIndex: "fan",
      render: () => <Tag color="blue">{t("dashboard.auto", { ns: "storageLocker" })}</Tag>,
    },
    {
      title: t("dashboard.lamp", { ns: "storageLocker" }),
      dataIndex: "lamp",
      render: () => <Tag color="gold">{t("dashboard.off", { ns: "storageLocker" })}</Tag>,
    },
    {
      title: `${t("dashboard.temp", { ns: "storageLocker" })} / ${t("dashboard.humi", { ns: "storageLocker" })}`,
      render: (_: any, record: StorageInfo) => (
        <Text>{record.temperature}°C / {record.humidity}%</Text>
      ),
    },
    {
      title: t("dashboard.address", { ns: "storageLocker" }),
      dataIndex: "address",
      key: "address",
      ellipsis: true,
    },
  ];

  const rowSelection = {
    selectedRowKeys,
    onChange: onSelectChange,
  };

  return (
    <div style={{ padding: 24, display: "flex", flexDirection: "column", gap: 24, height: "100%", overflow: "auto" }}>
      {/* Header & Controls */}
      <Card bordered={false} bodyStyle={{ padding: "16px 24px" }} style={{ boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
        <Row gutter={[24, 16]} align="middle">
          <Col xs={24} xl={4}>
            <Title level={4} style={{ margin: 0 }}>
              <ControlOutlined style={{ marginRight: 8, color: token.colorPrimary }} />
              {t("storageLocker:navigation.control")}
            </Title>
          </Col>
          
          <Col xs={24} md={18} xl={14}>
            <Space split={<Divider type="vertical" />} wrap>
              {/* Fan Control */}
              <Space.Compact>
                <span style={{ display: "flex", alignItems: "center", marginRight: 8 }}>
                  <SyncOutlined style={{ marginRight: 4 }} /> {t("dashboard.fan", { ns: "storageLocker" })}
                </span>
                <Select 
                  defaultValue="auto" 
                  style={{ width: 100 }} 
                  onChange={setFanMode}
                  options={[
                    { value: "auto", label: t("dashboard.auto", { ns: "storageLocker" }) },
                    { value: "on", label: t("dashboard.on", { ns: "storageLocker" }) },
                    { value: "off", label: t("dashboard.off", { ns: "storageLocker" }) },
                  ]} 
                />
                <Button type="primary" onClick={() => handleBatchControl("Fan", fanMode)}>{t("dashboard.execution", { ns: "storageLocker" })}</Button>
              </Space.Compact>

              {/* Lamp Control */}
              <Space.Compact>
                <span style={{ display: "flex", alignItems: "center", marginRight: 8 }}>
                  <BulbOutlined style={{ marginRight: 4 }} /> {t("dashboard.lamp", { ns: "storageLocker" })}
                </span>
                <Select 
                  defaultValue="led1_on" 
                  style={{ width: 120 }} 
                  onChange={setLampMode}
                  options={[
                    { value: "led1_on", label: t("dashboard.led1_on", { ns: "storageLocker" }) },
                    { value: "led1_off", label: t("dashboard.led1_off", { ns: "storageLocker" }) },
                    { value: "all_on", label: t("dashboard.all_on", { ns: "storageLocker" }) },
                  ]} 
                />
                <Button type="primary" onClick={() => handleBatchControl("Lamp", lampMode)}>{t("dashboard.execution", { ns: "storageLocker" })}</Button>
              </Space.Compact>

              {/* Lock Release */}
              <Button 
                danger 
                icon={<UnlockOutlined />} 
                onClick={() => handleBatchControl("Lock", "release")}
              >
                {t("dashboard.lockRelease", { ns: "storageLocker" })}
              </Button>
            </Space>
          </Col>

          <Col xs={24} md={6} xl={6} style={{ textAlign: "right" }}>
            <Input 
              placeholder={t("common:search")} 
              prefix={<SearchOutlined />} 
              style={{ width: 200 }}
              onChange={(e) => setSearchText(e.target.value)}
              allowClear
            />
          </Col>
        </Row>
      </Card>

      {/* Main Grid */}
      <Card bordered={false} bodyStyle={{ padding: 0 }} style={{ flex: 1, boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
        <Table 
          rowSelection={rowSelection} 
          columns={columns} 
          dataSource={filteredData} 
          rowKey="id"
          pagination={{ pageSize: 10 }}
          scroll={{ y: "calc(100vh - 350px)" }}
        />
      </Card>

      {/* Footer Info */}
      <div style={{ display: "flex", justifyContent: "space-between", padding: "0 8px" }}>
        <Text type="secondary">
          {t("common:total")}: {filteredData.length} {t("common:unit_device")} 
          {selectedRowKeys.length > 0 && (
            <span style={{ color: token.colorPrimary, marginLeft: 16 }}>
              {selectedRowKeys.length} {t("common:unit_device")} {t("common:selected")}
            </span>
          )}
        </Text>
        <Button icon={<ExportOutlined />} onClick={handleExportXlsx}>{t("common:exportXlsx")}</Button>
      </div>
    </div>
  );
}
